INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p2-wq-207', '2. World War I (1914-1918)', 'SL/HL', 'short_answer', 'P2-WAR', 15, 'To what extent was Germany responsible for the outbreak of World War I?', '• Band 5 (13-15): Evaluative argument engaging with the historiographical debate. Fischer: Germany deliberately sought war for expansion. Fay: collective responsibility. Winter: "Germany brought about WWI as part of a political community." Evidence for German responsibility: blank cheque, Weltpolitik, naval arms race, refusal of British conference proposal, Schlieffen Plan requiring rapid action. Evidence against sole responsibility: alliance system dynamics, Russian mobilisation, Austro-Hungarian aggression, Balkan nationalism, imperial rivalries. Must reach a substantiated judgement.
• Band 3 (7-9): Some engagement with historiography but limited evidence or imbalanced argument.
• Band 1 (1-3): Simple assertion about blame without supporting evidence.', 207);

INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p2-wq-208', '2. World War I (1914-1918)', 'SL/HL', 'short_answer', 'P2-WAR', 15, 'To what extent did the long-term causes of WWI make conflict inevitable by 1914?', '• Band 5 (13-15): Evaluative analysis of ANIMAL framework causes. Alliances: created encirclement fears, but terms were vague and did not compel action. Nationalism: glorified military strength, assimilated Social Darwinism, created atmosphere where war was an "opportunity." Imperialism: new arena for conflict (Moroccan Crises), but most imperial disputes resolved diplomatically. Militarism: arms race, Dreadnoughts, standing armies growing, war plans (Schlieffen) requiring rapid action. Must argue whether these made war inevitable or whether a crisis was still necessary. Short-term causes and miscalculations also needed to trigger actual war.
• Band 3 (7-9): Some discussion of causes but limited evaluation of inevitability.
• Band 1 (1-3): Simple listing of causes without analysis.', 208);

INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p2-wq-209', '2. World War I (1914-1918)', 'SL/HL', 'short_answer', 'P2-WAR', 15, 'Evaluate the significance of technology in determining the outcome of World War I.', '• Band 5 (13-15): Detailed analysis of specific technologies with evaluation of their impact. Machine guns: created stalemate (500 rpm), Britain massively outproduced Germany (120,900 vs 13,000 by 1918). Tanks: from 1916, initially basic but by 1918 5,000+ used effectively. Poison gas: less than 1% of fatalities, mainly psychological. Aircraft: reconnaissance then combat, supported ground troops. Submarines: U-boats sank 748,000 tons (1915), nearly starved Britain. Railways: critical for mobilisation and logistics. Must evaluate whether technology determined the outcome or whether other factors (US entry, blockade, leadership, morale) were more significant.
• Band 3 (7-9): Some relevant examples but limited evaluation of relative significance.
• Band 1 (1-3): Vague listing of technologies without analysis.', 209);

INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p2-wq-210', '2. World War I (1914-1918)', 'SL/HL', 'short_answer', 'P2-WAR', 15, 'How significant was the management of the war in determining its outcome?', '• Band 5 (13-15): Analysis of military leadership and strategic decisions. Failed strategies: Schlieffen Plan (logistics failure, railheads 135km behind), Verdun (10 months for 8km), Somme (54,740 casualties day 1). Successful adaptations: Allied combined arms (tanks + aircraft), convoy system against U-boats, Brusilov Offensive tactics. Ludendorff Offensive used innovative infiltration tactics but failed due to overextension. All plans assumed short war — if leaders knew the war''s length, they may have been more hesitant. Must evaluate management against other factors: resources, US entry, home front, disease (Spanish flu).
• Band 3 (7-9): Some discussion of military decisions but limited evaluation of significance.
• Band 1 (1-3): Vague assertions about leadership without specific examples.', 210);

INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p2-wq-211', '2. World War I (1914-1918)', 'SL/HL', 'short_answer', 'P2-WAR', 15, 'Did the impact of WWI make future European conflict more or less likely?', '• Band 5 (13-15): Evaluative argument considering multiple consequences. More likely: Treaty of Versailles resentment (war guilt, reparations, territorial losses), creation of many new democratic states prone to instability, economic disruption, rise of extremist ideologies (communism, fascism), failure of League of Nations, unresolved ethnic tensions. Less likely: horror of war should have deterred conflict, League of Nations created mechanisms for peaceful resolution, democratic spread, disarmament efforts. Must reach a clear judgement with specific evidence linking WWI outcomes to subsequent developments (Weimar instability, rise of Hitler, WWII).
• Band 3 (7-9): Some analysis of consequences but limited evaluation of likelihood of future conflict.
• Band 1 (1-3): Simple assertion without evidence.', 211);
